import type { ReactNode, Ref } from 'react';
import {
  Checkbox as AriaCheckbox,
  type CheckboxProps as AriaCheckboxProps,
} from 'react-aria-components';
import { CheckboxBase } from '@/vendor/untitled-ui/base/checkbox/checkbox';
import { cx } from '@/utils/cx';

export { CheckboxBase };

export interface CheckboxProps extends AriaCheckboxProps {
  ref?: Ref<HTMLLabelElement>;
  label?: ReactNode;
  hint?: ReactNode;
}

export const Checkbox = ({
  label,
  hint,
  className,
  ...ariaCheckboxProps
}: CheckboxProps) => {
  return (
    <AriaCheckbox
      {...ariaCheckboxProps}
      className={(state) =>
        cx(
          'flex items-start gap-2',
          state.isDisabled && 'cursor-not-allowed',
          typeof className === 'function' ? className(state) : className,
        )
      }
    >
      {({ isSelected, isIndeterminate, isDisabled, isFocusVisible }) => (
        <>
          <CheckboxBase
            isSelected={isSelected}
            isIndeterminate={isIndeterminate}
            isDisabled={isDisabled}
            isFocusVisible={isFocusVisible}
            className={label || hint ? 'mt-0.5' : ''}
          />
          {(label || hint) && (
            <div className="inline-flex flex-col">
              {label && (
                <p className="text-sm font-medium text-secondary select-none">
                  {label}
                </p>
              )}
              {hint && (
                <span
                  className="text-sm font-regular text-tertiary"
                  onClick={(event) => event.stopPropagation()}
                >
                  {hint}
                </span>
              )}
            </div>
          )}
        </>
      )}
    </AriaCheckbox>
  );
};
