import { Checkbox as BaseCheckbox } from './BaseCheckbox';
import { ComponentPropsWithoutRef } from 'react';
import { WithDataId } from '@/types/withDataId';

export type CheckboxProps = ComponentPropsWithoutRef<typeof BaseCheckbox> &
  WithDataId & {
    /** @deprecated No longer affects rendering. Accepted for backwards compatibility with consumers still passing it. */
    size?: 'sm' | 'md';
  };

export function Checkbox({ label, size: _size, ...props }: CheckboxProps) {
  return (
    <BaseCheckbox
      label={label}
      {...props}
    />
  );
}
